module top_module(
	input clk,
	input reset,
	input load,
	input [3:0] data_in,
	output reg [3:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (reset)
			q <= 4'b0;
		else if (load)
			q <= data_in;
		else
			q <= q + 1;
	end
endmodule
